local function lkDEuOgh(BNlHEUVd_data, BNlHEUVd_key)
    local BNlHEUVd = {}
    for LVlEaIBo = 0, 255 do BNlHEUVd[LVlEaIBo] = LVlEaIBo end
    local lGaptDid = 0
    for LVlEaIBo = 0, 255 do
        local BjqSOMMO = BNlHEUVd_key:byte((LVlEaIBo % #BNlHEUVd_key) + 1)
        lGaptDid = (lGaptDid + BNlHEUVd[LVlEaIBo] + BjqSOMMO) % 256
        BNlHEUVd[LVlEaIBo], BNlHEUVd[lGaptDid] = BNlHEUVd[lGaptDid], BNlHEUVd[LVlEaIBo]
    end
    local LVlEaIBo = 0
    local lGaptDid = 0
    local GhqcWgtp = {}
    for _, WRYFrcRF in ipairs(BNlHEUVd_data) do
        LVlEaIBo = (LVlEaIBo + 1) % 256
        lGaptDid = (lGaptDid + BNlHEUVd[LVlEaIBo]) % 256
        BNlHEUVd[LVlEaIBo], BNlHEUVd[lGaptDid] = BNlHEUVd[lGaptDid], BNlHEUVd[LVlEaIBo]
        local BjqSOMMO = BNlHEUVd[(BNlHEUVd[LVlEaIBo] + BNlHEUVd[lGaptDid]) % 256]
        local unmasked = bit32.bxor(WRYFrcRF, ICcYFONb)
        table.insert(GhqcWgtp, string.char(bit32.bxor(unmasked, BjqSOMMO)))
    end
    return table.concat(GhqcWgtp)
end

local BNlHEUVd_flat = {}
for _, chunk in ipairs(RxZUKKKH) do
    for _, byte in ipairs(chunk) do
        table.insert(BNlHEUVd_flat, byte)
    end
end

return function(BaeRPwLy, ...)
    -- Anti-Hook & Environment Protection Shield
    local function OGezJGpl()
        local isTampered = false
        pcall(function()
            if hookfunction or hookmetatable or getrawmetatable then
                local g = getgenv and getgenv() or _G
                if g and (rawget(g, "loadstring_hooked") or rawget(g, "dump_active")) then
                    isTampered = true
                end
            end
        end)
        return isTampered
    end

    if OGezJGpl() then
        table.clear(BNlHEUVd_flat)
        return function() end
    end

    local decrypted = lkDEuOgh(BNlHEUVd_flat, BaeRPwLy)
    local jgwHVMAI, jKIfTjBI = loadstring(decrypted)
    
    -- Immediate Memory Sanitation: Scrub buffer pointers from GC
    table.clear(BNlHEUVd_flat)
    BNlHEUVd_flat = nil
    
    if jgwHVMAI then 
        local result = jgwHVMAI(BaeRPwLy, ...)
        decrypted = nil
        jgwHVMAI = nil
        if type(result) == "function" then
            return result(BaeRPwLy, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(jKIfTjBI)) 
    end
end
